let _cache: RosterBox[] | null = null;
export function getSimRosterBoxes(): RosterBox[] {
  if (_cache) return _cache;
  _cache = SIM_ROWS.map((r) => ({
    name: r[0], season: r[1], pos: r[2],
    ppg: r[3], rpg: r[4], ast: r[5], stl: r[6], blk: r[7], mpg: r[8], teams: r[9],
  }));
  return _cache;
}
